16	pub mod read_task;
17	pub mod rx_buffer;
18	
19	use std::{
20	    ops::Neg,
21	    os::fd::{AsRawFd, RawFd},
22	    sync::{atomic::AtomicBool, Arc},
23	};
24	
25	use flume::Receiver;
26	use io_uring::{
27	    cqueue,
28	    opcode::{self, AsyncCancel2},
29	    squeue, types, IoUring, SubmissionQueue,
30	};
31	use nix::sys::eventfd::EfdFlags;
32	use zenoh_core::bail;
33	use zenoh_result::ZResult;
34	use zenoh_runtime::ZRuntime;
35	
36	use crate::{
37	    api::{
38	        reader::{fragmented_batch::FragmentedBatch, read_task::ReadTask, rx_buffer::RxBuffer},
39	        types::BufferCount,
40	    },
41	    batch_arena::BatchArena,
42	    reader::{
43	        buffer_group::{BufferGroup, GroupedArena},
44	        index::IndexGeneration,
45	        reactor_cmd::ReactorCmd,
46	        reservable_arena::ReservableArena,
47	        rx_context::Rx,
48	        rx_context_storage::RxContextStorage,
49	        submission::SubmissionIface,
50	        window::RxWindow,
51	        ReaderInner,
52	    },
53	};
54	
55	#[derive(Clone, Debug)]
56	pub struct Reader {
57	    inner: Arc<ReaderInner>,
58	    receiver: tokio::sync::watch::Receiver<String>,
59	}
60	
61	impl Drop for Reader {
62	    fn drop(&mut self) {
63	        tracing::debug!("Drop Reader: {:?}", self);
64	    }
65	}
66	
67	impl Reader {
68	    pub async fn setup_fragmented_read<Cb>(&self, fd: RawFd, mut callback: Cb) -> ZResult<ReadTask>
69	    where
70	        Cb: FnMut(FragmentedBatch) -> ZResult<()> + Send + 'static,
71	    {
72	        tracing::debug!("Setting up fragmented read task for fd: {fd}");
73	
74	        let mut window = RxWindow::default();
75	        let raw_callback = move |buffer| window.push(buffer, &mut callback);
76	
77	        ReadTask::new(fd, raw_callback, self.inner.submitter.clone()).await
78	    }
79	
80	    pub async fn setup_read<Cb>(&self, fd: RawFd, callback: Cb) -> ZResult<ReadTask>
81	    where
82	        Cb: FnMut(Arc<RxBuffer>) -> ZResult<()> + Send + 'static,
83	    {
84	        tracing::debug!("Setting up read task for fd: {fd}");
85	
86	        ReadTask::new(fd, callback, self.inner.submitter.clone()).await
87	    }
88	
89	    pub fn new(batch_size: usize, batch_count: BufferCount) -> ZResult<Self> {
90	        let batch_size = batch_size + batch_size / 2; // add some headroom to reduce ENOBUFS errors
91	
92	        // create eventfd to wake io_uring on demand by producing read events
93	        let waker = Arc::new(nix::sys::eventfd::EventFd::from_value_and_flags(
94	            0,
95	            EfdFlags::EFD_CLOEXEC,
96	        )?);
97	
98	        let c_waker = waker.clone();
99	
100	        let (sender, receiver) = flume::unbounded();
101	
102	        let submitter = SubmissionIface::new(waker, sender);
103	        let c_submitter = submitter.clone();
104	
105	        let exit_flag = Arc::new(AtomicBool::new(false));
106	
107	        let c_exit_flag = exit_flag.clone();
108	
109	        let (join_sender, mut join_receiver) = tokio::sync::watch::channel("".into());
110	        join_receiver.mark_unchanged();
111	
112	        let ring_worker = move || -> ZResult<()> {
113	            // Create Rx context storage
114	            let mut context_storage = RxContextStorage::new();
115	
116	            // io_uring read
117	            let ring: IoUring<squeue::Entry, cqueue::Entry> = IoUring::builder()
118	                .setup_submit_all()
119	                .setup_defer_taskrun()
120	                .setup_single_issuer()
121	                .build(4096)?;
122	            let arena = BatchArena::new(batch_size, batch_count, BufferCount::MAX)?;
123	            let arena = ReservableArena::new(arena, c_submitter);
124	            let arena = GroupedArena::new(arena);
125	
126	            // read for waker
127	            let waker_read =
128	                opcode::PollAdd::new(types::Fd(c_waker.as_raw_fd()), libc::POLLIN as _)
129	                    .build()
130	                    .user_data(IndexGeneration::INVALID_MAX)
131	                    .flags(io_uring::squeue::Flags::ASYNC);
132	
133	            unsafe { ring.submission_shared().push(&waker_read)? };
134	
135	            fn roll_cmds(
136	                receiver: &Receiver<ReactorCmd>,
137	                context_storage: &mut RxContextStorage,
138	                arena: &GroupedArena,
139	                sq: &mut SubmissionQueue<'_>,
140	                batch_count: BufferCount,
141	            ) -> ZResult<()> {
142	                // receive external submissions
143	                while let Ok(val) = receiver.try_recv() {
144	                    tracing::debug!("Cmd: {:?}", val);
145	
146	                    match val {
147	                        ReactorCmd::StartRx(fd, callback, set_once, error_sender) => {
148	                            let buffer_group = BufferGroup::new(arena, batch_count, sq)?;
149	                            let group_id = buffer_group.id();
150	
151	                            let rx_context = Rx::new(fd, callback, error_sender, buffer_group);
152	                            let index = context_storage.alloc(rx_context);
153	                            set_once.set(index)?;
154	
155	                            let recv = opcode::RecvMulti::new(types::Fd(fd), group_id)
156	                                .build()
157	                                .flags(io_uring::squeue::Flags::ASYNC)
158	                                .user_data(index.into());
159	
160	                            unsafe { sq.push(&recv)? }
161	                        }
162	                        ReactorCmd::StopRx(index_generation) => {
163	                            context_storage.free(index_generation);
164	
165	                            let cancel_builder =
166	                                types::CancelBuilder::user_data(index_generation.into()).all();
167	
168	                            let event = AsyncCancel2::new(cancel_builder)
169	                                .build()
170	                                .user_data(index_generation.into())
171	                                .flags(io_uring::squeue::Flags::ASYNC);
172	
173	                            unsafe { sq.push(&event)? }
174	                        }
175	                    }
176	                }
177	
178	                Ok(())
179	            }
180	
181	            loop {
182	                #[cfg(feature = "uring_trace")]
183	                let mut i = 0;
184	
185	                while let Some(e) = unsafe { ring.completion_shared() }.next() {
186	                    let mut sq = unsafe { ring.submission_shared() };
187	
188	                    roll_cmds(
189	                        &receiver,
190	                        &mut context_storage,
191	                        &arena,
192	                        &mut sq,
193	                        batch_count,
194	                    )?;
195	
196	                    match e.user_data() {
197	                        IndexGeneration::INVALID_MIN => {
198	                            tracing::debug!("Zero-user-data entry: {:?}", e);
199	                        }
200	                        IndexGeneration::INVALID_MAX => {
201	                            tracing::debug!("Waker event: {:?}", e);
202	                            let _ = c_waker.read()?;
203	                            unsafe { sq.push(&waker_read)? };
204	                        }
205	                        index => {
206	                            #[cfg(feature = "uring_trace")]
207	                            {
208	                                i += 1;
209	                            }
210	
211	                            let index = unsafe { IndexGeneration::new_unchecked(index) };
212	                            let to_submit =
213	                                Reader::multi(&context_storage, &e, index, &arena, &mut sq)?;
214	                            let len = sq.len() as u32;
215	                            if to_submit || len >= (batch_count / 2) as u32 {
216	                                drop(sq);
217	                                unsafe {
218	                                    ring.submitter().enter::<libc::sigset_t>(
219	                                        len,
220	                                        0,
221	                                        io_uring::EnterFlags::GETEVENTS.bits(),
222	                                        None,
223	                                    )?;
224	                                }
225	                            }
226	                        }
227	                    }
228	                }
229	
230	                #[cfg(feature = "uring_trace")]
231	                tracing::info!("Processed {} completion entries", i);
232	
233	                // receive external submissions
234	                let mut sq = unsafe { ring.submission_shared() };
235	                roll_cmds(
236	                    &receiver,
237	                    &mut context_storage,
238	                    &arena,
239	                    &mut sq,
240	                    batch_count,
241	                )?;
242	                drop(sq);
243	
244	                if c_exit_flag.load(std::sync::atomic::Ordering::SeqCst) {
245	                    break;
246	                }
247	
248	                // this wait can be interrupted by Self::wake_reader_thread
249	                ring.submit_and_wait(1)?;
250	            }
251	            Ok(())
252	        };
253	
254	        ZRuntime::RX.spawn_blocking(move || {
255	            if let Err(e) = ring_worker() {
256	                tracing::error!("Uring reactor error: {e}");
257	                let _ = join_sender.send(e.to_string());
258	            }
259	            tracing::debug!("Uring reactor thread finished!");
260	        });
261	
262	        let inner = Arc::new(ReaderInner::new(submitter, exit_flag));
263	
264	        Ok(Self {
265	            inner,
266	            receiver: join_receiver,
267	        })
268	    }
269	
270	    pub async fn wait_finished(&self) -> ZResult<()> {
271	        let mut r = self.receiver.clone();
272	        match r.changed().await {
273	            Ok(_) => Err((*r.borrow_and_update()).clone().into()),
274	            Err(_) => Ok(()),
275	        }
276	    }
277	
278	    fn multi(
279	        context_storage: &RxContextStorage,
280	        e: &io_uring::cqueue::Entry,
281	        index: IndexGeneration,
282	        arena: &GroupedArena,
283	        sq: &mut SubmissionQueue<'_>,
284	    ) -> ZResult<bool> {
285	        match context_storage.get(index) {
286	            Some(context) => match Reader::read_multi(e, index, context, sq) {
287	                Ok(val) => Ok(val),
288	                Err(e) => {
289	                    context.post_error(e);
290	                    Ok(false)
291	                }
292	            },
293	            None => Ok(Self::utilize_multi(e, arena)),
294	        }
295	    }
296	
297	    fn read_multi(
298	        e: &io_uring::cqueue::Entry,
299	        index: IndexGeneration,
300	        context: &Rx,
301	        sq: &mut SubmissionQueue<'_>,
302	    ) -> ZResult<bool> {
303	        let mut need_submit = false;
304	        if e.result() < 0 {
305	            tracing::debug!("Error entry: {:?}", e);
306	
307	            match e.result().neg() {
308	                libc::ENOBUFS => {
309	                    // We are out of buffers
310	                    tracing::debug!("ENOBUFS: Restart multishot receive for task {:?}", index);
311	
312	                    let recv =
313	                        opcode::RecvMulti::new(types::Fd(context.fd), context.buffer_group().id())
314	                            .build()
315	                            .flags(io_uring::squeue::Flags::ASYNC)
316	                            .user_data(index.into());
317	
318	                    unsafe { sq.push(&recv)? };
319	                    need_submit = true;
320	                }
321	                libc::ECANCELED => {
322	                    bail!("Rx task cancelled: {:?}", index);
323	                }
324	                libc::EALREADY => {
325	                    bail!("Operation already in progress for task {:?}", index);
326	                }
327	                unexpected => {
328	                    bail!("Task-related uring error: {}, task {:?}", unexpected, index);
329	                }
330	            }
331	        } else {
332	            if let Some(buf_id) = io_uring::cqueue::buffer_select(e.flags()) {
333	                #[cfg(feature = "uring_trace")]
334	                tracing::trace!("Read multishot entry: {:?}", e);
335	
336	                if !io_uring::cqueue::more(e.flags()) {
337	                    tracing::debug!("IORING_CQE_F_BUFFER: Restart multishot receive!!!");
338	
339	                    let recv =
340	                        opcode::RecvMulti::new(types::Fd(context.fd), context.buffer_group().id())
341	                            .build()
342	                            .flags(io_uring::squeue::Flags::ASYNC)
343	                            .user_data(index.into());
344	
345	                    unsafe { sq.push(&recv)? };
346	                    need_submit = true;
347	                }
348	
349	                let buf_len = e.result() as usize;
350	                let buffer = Arc::new(context.buffer_group().read_buffer(buf_id, buf_len, sq)?);
351	                context.run_callback(buffer);
352	            }
353	        }
354	        Ok(need_submit)
355	    }
356	
357	    fn utilize_multi(e: &io_uring::cqueue::Entry, arena: &GroupedArena) -> bool {
358	        if e.result() >= 0 {
359	            if let Some(buf_id) = io_uring::cqueue::buffer_select(e.flags()) {
360	                tracing::trace!("(utilize_multi) Read multishot entry: {:?}", e);
361	                arena.recycle_batch(buf_id);
362	                return true;
363	            }
364	        }
365	        false
366	    }
367	}
368

