251	    if link.inner.link.supports_priorities() {
252	        let (res, _, _) = select_all(pipeline.split().into_iter().map(|pipeline| {
253	            let mut link = link.clone();
254	            let cancellation_token = cancellation_token.clone();
255	            let keep_alive_tracker = keep_alive_tracker.clone();
256	            #[cfg(feature = "stats")]
257	            let stats = stats.clone();
258	            zenoh_runtime::ZRuntime::TX.spawn(async move {
259	                write_loop(
260	                    Some(pipeline.priority()),
261	                    pipeline,
262	                    &mut link,
263	                    keep_alive_tracker,
264	                    cancellation_token,
265	                    #[cfg(feature = "stats")]
266	                    stats,
267	                )
268	                .await
269	            })
270	        }))
271	        .await;
272	        res.unwrap()?;
273	    } else {
274	        write_loop(
275	            None,
276	            pipeline,
277	            link,
278	            keep_alive_tracker,
279	            cancellation_token,
