288	async fn write_loop(
289	    write_priority: Option<Priority>,
290	    mut pipeline: impl PipelineConsumer,
291	    link: &mut TransportLinkUnicastTx,
292	    keep_alive_tracker: TimeoutTracker,
293	    cancellation_token: CancellationToken,
294	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
295	) -> ZResult<()> {
296	    let task = async {
297	        loop {
298	            tokio::select! {
299	                pull = pipeline.pull() => {
300	                    let Some((mut batch, priority)) = pull else {
301	                        // The queue has been disabled: break the tx loop, drain the queue, and exit
302	                        break
303	                    };
304	                    debug_assert!(write_priority.is_none() || write_priority == Some(priority));
305	                    link.send_batch(&mut batch, write_priority).await?;
306	                    // inform the latest message tracker that a message has been sent
307	                    keep_alive_tracker.reset();
308	
309	                    #[cfg(feature = "stats")]
310	                    {
311	                        stats.inc_bytes(zenoh_stats::Tx, batch.len() as u64);
312	                        stats.inc_transport_message(zenoh_stats::Tx, batch.stats.t_msgs as u64);
313	                    }
314	
315	                    // Reinsert the batch into the queue
316	                    pipeline.refill(batch, priority);
317	                },
318	                _ = keep_alive_tracker.wait_if(write_priority.unwrap_or(Priority::Control) == Priority::Control) => {
319	                    // A timeout occurred, no control/data messages have been sent during
320	                    // the keep_alive period, we need to send a KeepAlive message
321	                    let message: TransportMessage = KeepAlive.into();
322	
323	                    #[allow(unused_variables)] // Used when stats feature is enabled
324	                    let n = link.send(&message, Some(Priority::Control)).await?;
325	
326	                    #[cfg(feature = "stats")]
327	                    {
328	                        stats.inc_bytes(zenoh_stats::Tx, n as u64);
329	                        stats.inc_transport_message(zenoh_stats::Tx, 1);
330	                    }
331	                }
332	            }
333	        }
334	        ZResult::Ok(())
335	    };
336	    if let Some(result) = cancellation_token.run_until_cancelled(task).await {
337	        result?;
338	    }
339	
340	    // Drain the transmission pipeline and write remaining bytes on the wire
341	    let mut batches = pipeline.drain();
342	    for (mut b, _) in batches.drain(..) {
343	        tokio::time::timeout(
344	            keep_alive_tracker.timeout(),
345	            link.send_batch(&mut b, write_priority),
346	        )
347	        .await
348	        .map_err(|_| {
349	            zerror!(
350	                "{link}: flush failed after {} ms",
351	                keep_alive_tracker.timeout().as_millis()
352	            )
353	        })??;
354	
355	        #[cfg(feature = "stats")]
356	        {
357	            stats.inc_bytes(zenoh_stats::Tx, b.len() as u64);
358	            stats.inc_transport_message(zenoh_stats::Tx, b.stats.t_msgs as u64);
359	        }
360	    }
361	
362	    Ok(())
363	}
