401	async fn rx_task_non_uring(
402	    link: &mut TransportLinkUnicastRx,
403	    transport: TransportUnicastUniversal,
404	    lease: Duration,
405	    rx_buffer_size: usize,
406	    cancellation_token: CancellationToken,
407	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
408	) -> ZResult<()> {
409	    // The pool of buffers
410	    let mtu = link.config.batch.mtu as usize;
411	    let mut n = rx_buffer_size / mtu;
412	    if n == 0 {
413	        tracing::debug!("RX configured buffer of {rx_buffer_size} bytes is too small for {link} that has an MTU of {mtu} bytes. Defaulting to {mtu} bytes for RX buffer.");
414	        n = 1;
415	    }
416	    let pool = RecyclingObjectPool::new(n, move || vec![0_u8; mtu].into_boxed_slice());
417	
418	    let lease_tracker = TimeoutTracker::new(lease);
419	    if link.link.supports_priorities() {
420	        let (res, _, _) = select_all((Priority::MAX as u8..=Priority::MIN as u8).map(|prio| {
421	            let mut link = link.clone();
422	            let transport = transport.clone();
423	            let cancellation_token = cancellation_token.clone();
424	            let lease_tracker = lease_tracker.clone();
425	            #[cfg(feature = "stats")]
426	            let stats = stats.clone();
427	            let pool = pool.clone();
428	            zenoh_runtime::ZRuntime::RX.spawn(async move {
429	                cancellation_token
430	                    .run_until_cancelled(read_loop(
431	                        Some(Priority::try_from(prio).unwrap()),
432	                        &mut link,
433	                        transport,
434	                        lease_tracker,
435	                        #[cfg(feature = "stats")]
436	                        stats,
437	                        &pool,
438	                    ))
439	                    .await
440	            })
441	        }))
442	        .await;
443	        res.unwrap().transpose()?;
444	        Ok(())
445	    } else {
446	        read_loop(
447	            None,
448	            link,
449	            transport,
450	            lease_tracker,
451	            #[cfg(feature = "stats")]
452	            stats,
453	            &pool,
454	        )
455	        .await
456	    }
457	}
