459	async fn read_loop<F: Fn() -> Box<[u8]>>(
460	    priority: Option<Priority>,
461	    link: &mut TransportLinkUnicastRx,
462	    transport: TransportUnicastUniversal,
463	    lease_tracker: TimeoutTracker,
464	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
465	    pool: &RecyclingObjectPool<Box<[u8]>, F>,
466	) -> ZResult<()> {
467	    async fn read<F: Fn() -> Box<[u8]>>(
468	        link: &mut TransportLinkUnicastRx,
469	        priority: Option<Priority>,
470	        pool: &RecyclingObjectPool<Box<[u8]>, F>,
471	    ) -> ZResult<RBatch<ZSlice>> {
472	        let batch = link
473	            .recv_batch(|| pool.try_take().unwrap_or_else(|| pool.alloc()), priority)
474	            .await?;
475	        Ok(batch)
476	    }
477	
478	    let l = Link::new_unicast(
479	        &link.link,
480	        link.config.priorities.clone(),
481	        link.config.reliability,
482	    );
483	    loop {
484	        tokio::select! {
485	            batch = read(link, priority, pool) => {
486	                let batch = batch?;
487	                lease_tracker.reset();
488	                #[cfg(feature = "stats")]
489	                {
490	                    let header_bytes = if l.is_streamed { 2 } else { 0 };
491	                    stats.inc_bytes(zenoh_stats::Rx, header_bytes + batch.len() as u64);
492	                }
493	                transport.read_messages(batch, &l, #[cfg(feature = "stats")] &stats)?;
494	            }
495	            _ = lease_tracker.wait_if(priority.unwrap_or(Priority::Control) == Priority::Control) => {
496	                bail!("{link}: expired after {} milliseconds", lease_tracker.timeout().as_millis());
497	            }
498	        }
499	    }
500	}
