502	struct TimeoutTrackerInner {
503	    timeout: Duration,
504	    waker: AtomicWaker,
505	    has_timed_out: AtomicBool,
506	    latest_reset: Mutex<Instant>,
507	    task: OnceLock<JoinHandle<()>>,
508	}
509	
510	#[derive(Clone)]
511	struct TimeoutTracker(Arc<TimeoutTrackerInner>);
512	
513	impl TimeoutTracker {
514	    fn new(timeout: Duration) -> TimeoutTracker {
515	        let now = Instant::now();
516	        let inner = Arc::new(TimeoutTrackerInner {
517	            timeout,
518	            waker: AtomicWaker::new(),
519	            has_timed_out: AtomicBool::new(false),
520	            latest_reset: Mutex::new(now),
521	            task: OnceLock::new(),
522	        });
523	        let tracker = Arc::downgrade(&inner);
524	        let task = tokio::spawn(async move {
525	            let mut latest_reset = now;
526	            loop {
527	                tokio::time::sleep_until((latest_reset + timeout).into()).await;
528	                let prev = latest_reset;
529	                let Some(tracker) = tracker.upgrade() else {
530	                    break;
531	                };
532	                latest_reset = *tracker.latest_reset.lock().unwrap();
533	                if latest_reset <= prev {
534	                    latest_reset = Instant::now();
535	                    tracker.has_timed_out.store(true, Ordering::Release);
536	                    tracker.waker.wake();
537	                }
538	            }
539	        });
540	        inner.task.set(task).unwrap();
541	        Self(inner)
542	    }
543	
544	    fn timeout(&self) -> Duration {
545	        self.0.timeout
546	    }
547	
548	    fn reset(&self) {
549	        *self.0.latest_reset.lock().unwrap() = Instant::now();
550	    }
551	
552	    async fn wait_if(&self, predicate: bool) {
553	        poll_fn(|cx| {
554	            if !predicate {
555	                return Poll::Pending;
556	            }
557	            self.0.waker.register(cx.waker());
558	            if self.0.has_timed_out.load(Ordering::Acquire) {
559	                self.0.has_timed_out.store(false, Ordering::Release);
560	                return Poll::Ready(());
561	            }
562	            Poll::Pending
563	        })
564	        .await
565	    }
566	}
567	
568	impl Drop for TimeoutTracker {
569	    fn drop(&mut self) {
570	        self.0.task.get().unwrap().abort();
571	    }
572	}
573	
574	#[cfg(all(feature = "uring", target_os = "linux"))]
575	async fn rx_task_uring(
576	    link: &mut TransportLinkUnicastRx,
577	    transport: TransportUnicastUniversal,
578	    lease: Duration,
579	    rx_buffer_size: usize,
580	    #[cfg(feature = "stats")] stats: zenoh_stats::LinkStats,
581	    cancellation_token: CancellationToken,
582	) -> ZResult<()> {
583	    // The pool of buffers
584	    let mtu = link.config.batch.mtu as usize;
585	    let mut n = rx_buffer_size / mtu;
586	    if n == 0 {
587	        tracing::debug!("RX configured buffer of {rx_buffer_size} bytes is too small for {link} that has an MTU of {mtu} bytes. Defaulting to {mtu} bytes for RX buffer.");
588	        n = 1;
589	    }
590	
591	    let pool = RecyclingObjectPool::new(n, move || vec![0_u8; mtu].into_boxed_slice());
592	
593	    let l = Link::new_unicast(
594	        &link.link,
595	        link.config.priorities.clone(),
596	        link.config.reliability,
597	    );
598	
599	    let batch_config = link.config.batch;
600	
601	    let r = transport
602	        .manager
603	        .state
604	        .uring
605	        .as_ref()
606	        .expect("uring is Some: checked by caller")
607	        .reader
608	        .clone();
609	
610	    let lease_tracker = TimeoutTracker::new(lease);
611	
612	    fn read_batch<TBuffer: BacktrackableReader + Buffer + Debug>(
613	        transport: &TransportUnicastUniversal,
614	        link: &Link,
615	        batch: RBatch<TBuffer>,
616	        #[cfg(feature = "stats")] stats: &zenoh_stats::LinkStats,
617	    ) -> ZResult<()> {
618	        #[cfg(feature = "stats")]
619	        {
620	            let header_bytes = 2;
621	            stats.inc_bytes(zenoh_stats::Rx, header_bytes + batch.len() as u64);
622	        }
623	        transport.read_messages(
624	            batch,
625	            link,
626	            #[cfg(feature = "stats")]
627	            stats,
628	        )
629	    }
630	
631	    let mut uring_read_task = {
632	        match link.link.is_streamed() {
633	            true => {
634	                let lt = lease_tracker.clone();
635	                let ring_cb = move |data: FragmentedBatch| {
636	                    lt.reset();
637	                    match data.defragment()? {
638	                        DefragmentationState::Single(slice) => {
639	                            let mut batch = RBatch::new(batch_config, slice);
640	                            batch.initialize_uring(|| {
641	                                pool.try_take().unwrap_or_else(|| pool.alloc())
642	                            })?;
643	                            read_batch(
644	                                &transport,
645	                                &l,
646	                                batch,
647	                                #[cfg(feature = "stats")]
648	                                &stats,
649	                            )
650	                        }
651	                        DefragmentationState::Fragmented(buf) => {
652	                            let mut batch = RBatch::new(batch_config, buf.reader());
653	                            match batch.initialize_uring(|| {
654	                                pool.try_take().unwrap_or_else(|| pool.alloc())
655	                            })? {
656	                                Some(decompressed_batch) => read_batch(
657	                                    &transport,
658	                                    &l,
659	                                    decompressed_batch,
660	                                    #[cfg(feature = "stats")]
661	                                    &stats,
662	                                ),
663	                                None => read_batch(
664	                                    &transport,
665	                                    &l,
666	                                    batch,
667	                                    #[cfg(feature = "stats")]
668	                                    &stats,
669	                                ),
670	                            }
671	                        }
672	                    }
673	                };
674	
675	                r.setup_fragmented_read(link.link.get_fd()?, ring_cb)
676	                    .await?
677	            }
678	            false => {
679	                let lt = lease_tracker.clone();
680	                let ring_cb = move |data: Arc<RxBuffer>| {
681	                    lt.reset();
682	                    let slice: ZSlice = data.into();
683	                    let mut batch = RBatch::new(batch_config, slice);
684	                    batch.initialize_uring(|| pool.try_take().unwrap_or_else(|| pool.alloc()))?;
685	
686	                    read_batch(
687	                        &transport,
688	                        &l,
689	                        batch,
690	                        #[cfg(feature = "stats")]
691	                        &stats,
692	                    )
693	                };
694	
695	                r.setup_read(link.link.get_fd()?, ring_cb).await?
696	            }
697	        }
698	    };
699	
700	    let result = tokio::select! {
701	        e = uring_read_task.read_error() => {
702	            tracing::debug!("Uring RX task stopped by uring task error event");
703	            Err(e)
704	        },
705	        finished = r.wait_finished() => {
706	            tracing::debug!("Uring RX task stopped by uring finished event: {:?}", finished);
707	            finished
708	        }
709	        _ = lease_tracker.wait_if(true) => {
710	            tracing::debug!("Uring RX task stopped by lease timeout");
711	            bail!("{link}: expired after {} milliseconds", lease.as_millis());
712	        }
713	        _ = cancellation_token.cancelled() => {
714	            tracing::debug!("Uring RX task stopped by cancellation event");
715	            Ok(())
716	        }
717	    };
718	
719	    uring_read_task.stop().await;
720	
721	    result
722	}
